from typing import List
from collections import deque


class Solution:
    def canReach(self, arr: List[int], start: int) -> bool:
        n = len(arr)
        if arr[start] == 0:
            return True
        visited = {start}
        queue = deque([start])
        while queue:
            i = queue.popleft()
            if arr[i] == 0:
                return True
            for nxt in (i + arr[i], i - arr[i]):
                if 0 <= nxt < n and nxt not in visited:
                    visited.add(nxt)
                    queue.append(nxt)
        return False


# Brute-force-ish oracle: plain DFS recursion WITH visited (correct reference)
class Oracle:
    def canReach(self, arr, start):
        n = len(arr)
        seen = set()
        def dfs(i):
            if not (0 <= i < n) or i in seen:
                return False
            if arr[i] == 0:
                return True
            seen.add(i)
            return dfs(i + arr[i]) or dfs(i - arr[i])
        return dfs(start)


import random

def run():
    s = Solution()
    o = Oracle()
    # samples
    assert s.canReach([4,2,3,0,3,1,2], 5) is True
    assert s.canReach([3,0,2,1,2], 2) is False
    # edge cases
    assert s.canReach([0], 0) is True            # start on zero
    assert s.canReach([1], 0) is False           # single non-zero, jumps out
    assert s.canReach([0,1], 1) is True          # reach zero by jumping left
    assert s.canReach([1,1,1], 0) is False       # no zero anywhere... wait there is none -> false
    assert s.canReach([2,1,0], 0) is True
    # random differential test
    for _ in range(20000):
        n = random.randint(1, 12)
        arr = [random.randint(0, n-1) for _ in range(n)]
        start = random.randint(0, n-1)
        assert s.canReach(arr, start) == o.canReach(arr, start), (arr, start)
    print("ALL PASS")

run()
